const lead = $input.all()[0].json;

const AREA_ATUACAO = {
  PRIORIDADE_1: {
    descricao: 'Todo o município do Rio de Janeiro',
    peso_score: 25,
    bairros: [
      'zona norte', 'zona sul', 'zona oeste', 'centro', 'barra',
      'tijuca', 'méier', 'madureira', 'campo grande', 'bangu',
      'copacabana', 'botafogo', 'flamengo', 'catete', 'laranjeiras',
      'santa cruz', 'realengo', 'jacarepaguá', 'recreio', 'ilha',
      'penha', 'vicente de carvalho', 'vila isabel', 'andaraí',
      'grajaú', 'todos os santos', 'cachambi', 'piedade',
      'cascadura', 'quintino', 'engenho novo', 'riachuelo'
    ]
  },
  PRIORIDADE_2: {
    descricao: 'Baixada Fluminense (apenas com viabilidade operacional)',
    peso_score: 15,
    municipios: ['nova iguaçu', 'duque de caxias', 'são joão de meriti', 'nilópolis', 'belford roxo', 'mesquita']
  },
  PRIORIDADE_3: {
    descricao: 'Niterói e São Gonçalo (apenas projetos específicos)',
    peso_score: 8,
    municipios: ['niterói', 'são gonçalo']
  }
};

let score = 0;
const location = (lead.bairro || lead.cidade || '').toLowerCase();

if (AREA_ATUACAO.PRIORIDADE_1.bairros.some(b => location.includes(b))) {
    score += AREA_ATUACAO.PRIORIDADE_1.peso_score;
} else if (AREA_ATUACAO.PRIORIDADE_2.municipios.some(m => location.includes(m))) {
    score += AREA_ATUACAO.PRIORIDADE_2.peso_score;
} else if (AREA_ATUACAO.PRIORIDADE_3.municipios.some(m => location.includes(m))) {
    score += AREA_ATUACAO.PRIORIDADE_3.peso_score;
}

lead.score = score;
return { json: lead };
